            width: 300px;
            height: 400px;
            background-color: #353535;
            border-radius: 10px;
            overflow: hidden;
            transform-style: preserve-3d;
            transition: transform 0.5s ease;
        }

        .card:hover {
            transform: rotateY(180deg);
        }

        .card__face {
            position: absolute;
            width: 100%;
            height: 100%;
            backface-visibility: hidden;
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 24px;
            color: #ffffff;
            font-weight: bold;
        }

        .card__face--front {
            background-color: #272727;
            transform: rotateY(0deg);
        }

        .card__face--back {
            background-color: #272727;
            transform: rotateY(180deg);
        }

        .card__shadow {
            position: absolute;
            width: 100%;
            height: 100%;
            background-color: rgba(0, 0, 0, 0.5);
            backdrop-filter: blur(10px);
            z-index: -1;
        }

        @keyframes roadAnimation {
            0% {
                transform: translateX(-50%) translateY(-50%) rotateY(0deg);
            }
            50% {
                transform: translateX(-50%) translateY(-50%) rotateY(180deg);
            }
            100% {
                transform: translateX(-50%) translateY(-50%) rotateY(0deg);
            }
        }

        .card__road {
            position: absolute;
            width: 100%;
            height: 100%;
            background-image: linear-gradient(to right, #ffffff 0%, #272727 100%);
            animation: roadAnimation 2s infinite linear;
        }
    </style>
</head>
<body>
    <div class="card">
        <div class="card__face card__face--front">
            <div class="card__road"></div>
            <p>Speed Limit: 60 km/h</p>
        </div>
        <div class="card__face card__face--back">
            <div class="card__road"></div>
            <p>Speed Limit: 60 km/h</p>
        </div>
        <div class="card__shadow"></div>
    </div>
</body>
</html>
