<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Glitch Button</title>
    <style>
        .glitch-button {
            position: relative;
            display: inline-block;
            padding: 1em 2em;
            font-size: 1.2em;
            color: #ffffff;
            background-color: #1df2f0;
            border: none;
            cursor: pointer;
            overflow: hidden;
            transition: transform 0.3s ease, box-shadow 0.3s ease;
        }

        .glitch-button::before,
        .glitch-button::after {
            content: attr(data-text);
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            color: #ffffff;
            font-size: 1.2em;
            text-align: center;
            line-height: 1;
            white-space: nowrap;
            opacity: 0;
            transition: opacity 0.3s ease, transform 0.3s ease;
        }

        .glitch-button::before {
            animation: glitch 2s infinite alternate;
        }

        .glitch-button::after {
            animation: glitch 2s infinite alternate;
            transform: translateX(1px);
        }

        @keyframes glitch {
            0%, 100% {
                transform: skewX(0deg);
            }
            50% {
                transform: skewX(10deg);
            }
        }

        .glitch-button:hover {
            transform: scale(1.1);
            box-shadow: 0 0 10px rgba(255, 255, 255, 0.5);
        }
    </style>
</head>
<body>
    <button class="glitch-button" data-text="Click Me!">
        <span class="glitch-button__text">Click Me!</span>
    </button>
</body>
</html>
