            color: white;
            background-color: #3F8EFC;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            transition: background-color 0.5s ease, color 0.5s ease;
        }

        .installer-button:hover {
            background-color: #87E544;
            color: white;
        }

        .progress-bar {
            width: 100%;
            height: 10px;
            background-color: #FFFFFF;
            position: relative;
            margin-top: 10px;
        }

        .progress-bar::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            height: 100%;
            background-color: #3F8EFC;
            width: 0;
            transition: width 0.5s ease;
        }

        .thank-you-text {
            margin-top: 10px;
            font-size: 14px;
            color: #3F8EFC;
        }
    </style>
</head>
<body>
    <button class="installer-button">Download Now</button>
    <div class="progress-bar">
        <div class="progress-bar-fill"></div>
    </div>
    <p class="thank-you-text">Thank you for downloading!</p>

    <script>
        // Simulate download progress
        const progressBar = document.querySelector('.progress-bar-fill');
        let progress = 0;

        function updateProgress() {
            progress += Math.random() * 10; // Random progress increase
            if (progress > 100) progress = 100; // Cap at 100%
            progressBar.style.width = `${progress}%`;
        }

        setInterval(updateProgress, 1000); // Update every second
    </script>
</body>
</html>
