            left: 50%;
            transform: translate(-50%, -50%);
            border-radius: 50%;
            box-shadow: 0 0 20px rgba(0, 0, 0, 0.1), 0 0 40px rgba(0, 0, 0, 0.05);
        }

        .spinner::before {
            width: 90%;
            height: 90%;
            background-color: #ffffff;
            animation: spinInner 2s linear infinite;
        }

        .spinner::after {
            width: 80%;
            height: 80%;
            background-color: #000000;
            animation: spinOuter 2s linear infinite;
        }

        @keyframes spinInner {
            0% {
                transform: rotateY(0deg);
            }
            100% {
                transform: rotateY(360deg);
            }
        }

        @keyframes spinOuter {
            0% {
                transform: rotateY(0deg);
            }
            100% {
                transform: rotateY(-360deg);
            }
        }
    </style>
</head>
<body>
