```css
<style>
.starfield {
  position: relative;
  width: 100%;
  height: 100vh;
  overflow: hidden;
}

.layer {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 100%;
  height: 100%;
  clip-path: circle(50% at 50% 50%);
  animation: warp 10s linear infinite;
}

@keyframes warp {
  0% {
    transform: translate(-50%, -50%) scale(1);
    clip-path: circle(50% at 50% 50%);
  }
  50% {
    transform: translate(-50%, -50%) scale(1.1);
    clip-path: circle(60% at 50% 50%);
  }
  100% {
    transform: translate(-50%, -50%) scale(1);
    clip-path: circle(50% at 50% 50%);
  }
}

.layer:nth-child(even) {
  animation-delay: -5s;
}

.layer:nth-child(odd) {
  animation-delay: 0s;
}

.layer::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(to right bottom, #ff7e5f, #feb47b);
  background-size: 100% 100%;
  animation: parallax 10s linear infinite;
}

@keyframes parallax {
  0% {
    background-position: 0 0;
  }
  50% {
    background-position: 100% 100%;
  }
  100% {
    background-position: 0 0;
  }
}

.layer::after {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
